module RefModule(
    input [3:0] MULTIPLICAND,
    input [3:0] MULTIPLIER,
    output reg [7:0] PRODUCT
);reg [3:0] obf_m;
reg [7:0] p;

always @(*) begin
    p = 0;
    for (obf_m = 0; obf_m < 4; obf_m = obf_m + 1) begin
        if (MULTIPLIER[obf_m] == 1) begin
            p = p + (MULTIPLICAND << obf_m);
        end
    end
end

assign PRODUCT = p;

endmodule
